entry.content:
###二、完善webpack.config.js配置（2） 4. 为了开发-开发工具官网https://webpack.js.org有介绍三种开发工具 webpack’s Watch Mode webpack-dev-server webpack-dev-middleware 这里选用一个较为常用的—webpack-dev-server首先下载依赖 1$ npm install --save-dev webpack-dev-server webpack.config.js123456789101112131415161718 const path = require(&apos;path&apos;); const webpack = require(&apos;webpack&apos;); const HtmlWebpackPlugin = require(&apos;html-webpack-plugin&apos;); const CleanWebpackPlugin = require(&apos;clean-webpack-plugin&apos;); module.exports = &#123; entry: &apos;./src/index.js&apos;, output: &#123; filename: &apos;[name].[chunkhash:8].js&apos;, path: path.resolve(__dirname, &apos;dist&apos;) &#125;,+ devServer: &#123;+ contentBase: &apos;./dist&apos;+ &#125;, plugins: [ new CleanWebpackPlugin([&apos;dist&apos;]), ], &#125;; 在package.json脚本行添加 &quot;start&quot;: &quot;webpack-dev-server --open&quot;最后通过npm run start 就可以开启一个简单的本地服务 5. 为了开发-热加载这里使用webpack-dev-server配置热加载注意：热加载和chunkhash冲突 这里改为hashwebpack.config.js1234567891011121314151617181920212223 const path = require(&apos;path&apos;); const webpack = require(&apos;webpack&apos;); const HtmlWebpackPlugin = require(&apos;html-webpack-plugin&apos;); const CleanWebpackPlugin = require(&apos;clean-webpack-plugin&apos;); module.exports = &#123; entry: &apos;./src/index.js&apos;, output: &#123; filename: &apos;[name].[hash:8].js&apos;, path: path.resolve(__dirname, &apos;dist&apos;) &#125;,+ devServer: &#123;+ contentBase: &apos;./dist&apos;+ historyApiFallback: true,//任意的跳转或404响应可以指向首页；+ inline: true, //一般启用inline方式热更新+ hot: true,+ &#125;, plugins: [ new CleanWebpackPlugin([&apos;dist&apos;]),+ new webpack.NamedModulesPlugin(), //热加载显示模块的相对路径+ new webpack.HotModuleReplacementPlugin(), //启用热加载模块 ], &#125;; 这样就把热加载项配置好了当然热加载还不止这点 -&gt;热加载参考 6. 添加postcss-loader1234567891011121314151617181920212223242526272829303132&#123; test: /\.css$/, use: [ require.resolve(&apos;style-loader&apos;), &#123; loader: require.resolve(&apos;css-loader&apos;), options: &#123; importLoaders: 1, //接下来的需要的loader个数 modules: true, //模块化css localIdentName: &apos;[local]_[hash:base64:5]&apos; //css名称 &#125;, &#125;, &#123; loader: require.resolve(&apos;postcss-loader&apos;), options: &#123; ident: &apos;postcss&apos;, plugins: () =&gt; [ require(&apos;postcss-flexbugs-fixes&apos;), autoprefixer(&#123; browsers: [ &apos;&gt;1%&apos;, &apos;last 4 versions&apos;, &apos;Firefox ESR&apos;, &apos;not ie &lt; 9&apos;, // React doesn&apos;t support IE8 anyway ], flexbox: &apos;no-2009&apos;, &#125;), ], &#125;, &#125;, ],&#125;, 7. 公共文件抽取DllPlugin大大加快编译速度首先我选择在根目录下新增一个webpack.dll.config.js文件并配置好内容123456789101112131415161718192021const path = require(&quot;path&quot;);const webpack = require(&quot;webpack&quot;);const _package = require(&apos;./package.json&apos;); // 引入package.jsonmodule.exports = &#123; entry: &#123; vendor: Object.keys(_package.dependencies) // 遍历package.json的所有依赖包 &#125;, output: &#123; path: path.join(__dirname, &apos;build&apos;), // 生成的文件存放路径 filename: &apos;[name].dll.js&apos;, // 生成的文件名字(默认为vendor.dll.js) library: &apos;[name]_library&apos; // 生成文件的映射关系，与下面DllPlugin中配置对应 &#125;, plugins: [ new webpack.DllPlugin(&#123; // 会生成一个json文件，里面是关于dll.js的一些配置信息 path: path.join(__dirname, &apos;public&apos;, &apos;[name]-manifest.json&apos;), name: &apos;[name]_library&apos;, // 与上面output中配置对应 context: __dirname // 上下文环境路径 &#125;) ]&#125;; 然后在package.json中配置启动 &quot;dll&quot;:&quot;webpack --config webpack.dll.config.js --progress&quot; 执行 npm run dll =&gt;生成依赖映射文件 最后在我们的webpack.dev.config.jsplugin 中加入DllReferencePlugin 1234new webpack.DllReferencePlugin(&#123; context: __dirname, manifest: path.join(__dirname, &quot;public&quot;,&quot;vendor-manifest.json&quot;)//dll生成的映射json路径 &#125;), 注意：我们需要把dll生成的公共js文件需要在bundle.js之前引入才行现在我们就可以开始npm run dev 实现快速编译了 **8. 配置eslint帮助我们检查代码，大大提高开发效率 -&gt; Eslint参考文献 -&gt; Eslint中文 这个配置因人而异，很多编辑器可以直接引入eslint插件实现代码检测，就无需配置这个了，反而影响编译速度 start：老规矩先装依赖(这里使用airbnb编译规则，有自己的规则可以在.eslintrc相关文件上编写自己的rules)12npm install --save-dev eslinteslint --init//这里根据需求走 我们选择popular -&gt; bnb 由于是代码检测工具所以我们需要放在js执行前 1234567891011121314 &#123; test: /\.(js|jsx|mjs)$/, enforce: &apos;pre&apos;, use: [ &#123; options: &#123; formatter: eslintFormatter,//这个输出格式可以网上找或者自己写，传入一个eslint解析的结果，需要返回打印内容可以使用 &apos;eslint-friendly-formater&apos; eslintPath: require.resolve(&apos;eslint&apos;), &#125;, loader: require.resolve(&apos;eslint-loader&apos;), &#125;, ], include: `$&#123;__dirname&#125;`,&#125;, eslintFormatter.js 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465666768697071727374757677&apos;use strict&apos;;const chalk = require(&apos;chalk&apos;);const table = require(&apos;text-table&apos;);function isError(message) &#123; if (message.fatal || message.severity === 2) &#123; return true; &#125; return false;&#125;function formatter(results) &#123; let output = &apos;
&apos;; let hasErrors = false; let reportContainsErrorRuleIDs = false; results.forEach(result =&gt; &#123; let messages = result.messages; if (messages.length === 0) &#123; return; &#125; messages = messages.map(message =&gt; &#123; let messageType; if (isError(message)) &#123; messageType = &apos;error&apos;; hasErrors = true; if (message.ruleId) &#123; reportContainsErrorRuleIDs = true; &#125; &#125; else &#123; messageType = &apos;warn&apos;; &#125; let line = message.line || 0; let position = chalk.bold(&apos;Line &apos; + line + &apos;:&apos;); return [ &apos;&apos;, position, messageType, message.message.replace(/\.$/, &apos;&apos;), chalk.underline(message.ruleId || &apos;&apos;), ]; &#125;); // if there are error messages, we want to show only errors // if (hasErrors) &#123; // messages = messages.filter(m =&gt; m[2] === &apos;error&apos;); // &#125; // add color to rule keywords messages.forEach(m =&gt; &#123; console.log(m[4]) m[4] = m[2] === &apos;error&apos; ? chalk.red(m[4]) : chalk.yellow(m[4]); m.splice(2, 1); &#125;); let outputTable = table(messages, &#123; align: [&apos;l&apos;, &apos;l&apos;, &apos;l&apos;], stringLength(str) &#123; return str.length; &#125;, &#125;); output += `$&#123;outputTable&#125;

`; &#125;); // if (reportContainsErrorRuleIDs) &#123; // output += // &apos;Search for the &apos; + // chalk.underline(chalk.red(&apos;keywords&apos;)) + // &apos; to learn more about each error.&apos;; // &#125; return output;&#125;module.exports = formatter; OK,基本配置完结，现在基本的功能都已经有了，再来就是可以封装一下方法啥的！
